class Solution:
    def numberOfSubstrings(self, s):
        last = {'a': -1, 'b': -1, 'c': -1}
        total = 0
        for i, ch in enumerate(s):
            last[ch] = i
            total += 1 + min(last['a'], last['b'], last['c'])
        return total

