var numberOfSubstrings = function(s) {
    const last = { a: -1, b: -1, c: -1 };
    let total = 0;
    for (let i = 0; i < s.length; i++) {
        last[s[i]] = i;
        const m = Math.min(last.a, last.b, last.c);
        total += 1 + m;
    }
    return total;
};
